B.avo=new A.ib("What moves price?","\u0427\u0442\u043e \u0434\u0432\u0438\u0433\u0430\u0435\u0442 \u0446\u0435\u043d\u0443?","O que move o pre\xe7o?","\xbfQu\xe9 mueve el precio?","Price changes when buyers and sellers disagree on value. More buyers push price up; more sellers push it down.","\u0426\u0435\u043d\u0430 \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f, \u043a\u043e\u0433\u0434\u0430 \u043f\u043e\u043a\u0443\u043f\u0430\u0442\u0435\u043b\u0438 \u0438 \u043f\u0440\u043e\u0434\u0430\u0432\u0446\u044b \u043d\u0435 \u0441\u043e\u0433\u043b\u0430\u0441\u043d\u044b \u0432 \u043e\u0446\u0435\u043d\u043a\u0435. \u0411\u043e\u043b\u044c\u0448\u0435 \u043f\u043e\u043a\u0443\u043f\u0430\u0442\u0435\u043b\u0435\u0439 \u2014 \u0446\u0435\u043d\u0430 \u0440\u0430\u0441\u0442\u0451\u0442; \u0431\u043e\u043b\u044c\u0448\u0435 \u043f\u0440\u043e\u0434\u0430\u0432\u0446\u043e\u0432 \u2014 \u043f\u0430\u0434\u0430\u0435\u0442.","O pre\xe7o muda quando compradores e vendedores discordam sobre o valor. Mais compradores elevam o pre\xe7o; mais vendedores o derrubam.","El precio cambia cuando compradores y vendedores no coinciden en el valor. M\xe1s compradores suben el precio; m\xe1s vendedores lo bajan.",B.Yo)
B.avq=new A.ib("Bull vs Bear market","\u0411\u044b\u0447\u0438\u0439 vs \u043c\u0435\u0434\u0432\u0435\u0436\u0438\u0439 \u0440\u044b\u043d\u043e\u043a","Mercado de alta vs baixa","Mercado alcista vs bajista","A bull market trends upward with optimism. A bear market trends downward with pessimism. Most traders adapt strategy to the environment.","\u0411\u044b\u0447\u0438\u0439 \u0440\u044b\u043d\u043e\u043a \u0440\u0430\u0441\u0442\u0451\u0442 \u043d\u0430 \u043e\u043f\u0442\u0438\u043c\u0438\u0437\u043c\u0435. \u041c\u0435\u0434\u0432\u0435\u0436\u0438\u0439 \u2014 \u043f\u0430\u0434\u0430\u0435\u0442 \u043d\u0430 \u043f\u0435\u0441\u0441\u0438\u043c\u0438\u0437\u043c\u0435. \u0411\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u0442\u0440\u0435\u0439\u0434\u0435\u0440\u043e\u0432 \u0430\u0434\u0430\u043f\u0442\u0438\u0440\u0443\u044e\u0442 \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044e \u043f\u043e\u0434 \u0441\u0440\u0435\u0434\u0443.","Um mercado de alta sobe com otimismo. Um de baixa cai com pessimismo. A maioria dos traders adapta a estrat\xe9gia ao ambiente.","Un mercado alcista sube con optimismo. Uno bajista cae con pesimismo. La mayor\xeda adapta la estrategia al entorno.",B.kx)
B.avm=new A.ib("Volatility","\u0412\u043e\u043b\u0430\u0442\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u044c","Volatilidade","Volatilidad","Volatility measures how fast and how far price moves. High volatility means bigger swings \u2014 more opportunity and more risk.","\u0412\u043e\u043b\u0430\u0442\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0431\u044b\u0441\u0442\u0440\u043e \u0438 \u0434\u0430\u043b\u0435\u043a\u043e \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044f \u0446\u0435\u043d\u0430. \u0412\u044b\u0441\u043e\u043a\u0430\u044f \u0432\u043e\u043b\u0430\u0442\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u2014 \u0431\u043e\u043b\u044c\u0448\u0435 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0441\u0442\u0435\u0439 \u0438 \u0440\u0438\u0441\u043a\u0430.","Volatilidade mede qu\xe3o r\xe1pido e qu\xe3o longe o pre\xe7o se move. Alta volatilidade significa maiores oscila\xe7\xf5es \u2014 mais oportunidade e risco.","La volatilidad mide qu\xe9 tan r\xe1pido y lejos se mueve el precio. Alta volatilidad = mayores swings: m\xe1s oportunidad y m\xe1s riesgo.",B.uU)
B.YO=new A.aE(984725,"MaterialIcons",null,!1)
B.avn=new A.ib("Liquidity","\u041b\u0438\u043a\u0432\u0438\u0434\u043d\u043e\u0441\u0442\u044c","Liquidez","Liquidez","Liquidity is how easily you can buy or sell without moving price. Major markets like EUR/USD or S&P 500 tend to have high liquidity.","\u041b\u0438\u043a\u0432\u0438\u0434\u043d\u043e\u0441\u0442\u044c \u2014 \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043b\u0435\u0433\u043a\u043e \u043a\u0443\u043f\u0438\u0442\u044c \u0438\u043b\u0438 \u043f\u0440\u043e\u0434\u0430\u0442\u044c \u0431\u0435\u0437 \u0441\u0434\u0432\u0438\u0433\u0430 \u0446\u0435\u043d\u044b. \u041a\u0440\u0443\u043f\u043d\u044b\u0435 \u0440\u044b\u043d\u043a\u0438 \u0432\u0440\u043e\u0434\u0435 EUR/USD \u0438\u043b\u0438 S&P 500 \u043e\u0431\u044b\u0447\u043d\u043e \u0432\u044b\u0441\u043e\u043a\u043e\u043b\u0438\u043a\u0432\u0438\u0434\u043d\u044b.","Liquidez \xe9 qu\xe3o facilmente voc\xea pode comprar ou vender sem mover o pre\xe7o. Mercados como EUR/USD ou S&P 500 tendem a ter alta liquidez.","La liquidez es qu\xe9 tan f\xe1cil puedes comprar o vender sin mover el precio. Mercados como EUR/USD o S&P 500 suelen ser muy l\xedquidos.",B.YO)
B.Yj=new A.aE(58710,"MaterialIcons",null,!1)
B.avk=new A.ib("Market sessions","\u0422\u043e\u0440\u0433\u043e\u0432\u044b\u0435 \u0441\u0435\u0441\u0441\u0438\u0438","Sess\xf5es de mercado","Sesiones de mercado","Asian, European, and US sessions have different activity levels. Volatility often increases when sessions overlap.","\u0410\u0437\u0438\u0430\u0442\u0441\u043a\u0430\u044f, \u0435\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u043a\u0430\u044f \u0438 \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u0430\u044f \u0441\u0435\u0441\u0441\u0438\u0438 \u043e\u0442\u043b\u0438\u0447\u0430\u044e\u0442\u0441\u044f \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u044c\u044e. \u0412\u043e\u043b\u0430\u0442\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0447\u0430\u0441\u0442\u043e \u0440\u0430\u0441\u0442\u0451\u0442 \u043f\u0440\u0438 \u0438\u0445 \u043f\u0435\u0440\u0435\u0441\u0435\u0447\u0435\u043d\u0438\u0438.","Sess\xf5es asi\xe1tica, europeia e americana t\xeam n\xedveis diferentes de atividade. A volatilidade costuma aumentar quando se sobrep\xf5em.","Las sesiones asi\xe1tica, europea y estadounidense tienen distinta actividad. La volatilidad suele subir cuando se solapan.",B.Yj)
B.avs=new A.ib("Spread","\u0421\u043f\u0440\u0435\u0434","Spread","Spread","The spread is the gap between buy and sell price. It is a cost of trading \u2014 tighter spreads mean lower friction.","\u0421\u043f\u0440\u0435\u0434 \u2014 \u0440\u0430\u0437\u043d\u0438\u0446\u0430 \u043c\u0435\u0436\u0434\u0443 \u0446\u0435\u043d\u043e\u0439 \u043f\u043e\u043a\u0443\u043f\u043a\u0438 \u0438 \u043f\u0440\u043e\u0434\u0430\u0436\u0438. \u042d\u0442\u043e \u0441\u0442\u043e\u0438\u043c\u043e\u0441\u0442\u044c \u0442\u043e\u0440\u0433\u043e\u0432\u043b\u0438 \u2014 \u043c\u0435\u043d\u044c\u0448\u0438\u0439 \u0441\u043f\u0440\u0435\u0434 \u043e\u0437\u043d\u0430\u0447\u0430\u0435\u0442 \u043c\u0435\u043d\u044c\u0448\u0435 \u0438\u0437\u0434\u0435\u0440\u0436\u0435\u043a.","O spread \xe9 a diferen\xe7a entre pre\xe7o de compra e venda. \xc9 um custo de trading \u2014 spreads menores significam menos atrito.","El spread es la diferencia entre compra y venta. Es un costo de trading: spreads m\xe1s estrechos = menos fricci\xf3n.",B.uJ)
B.Yg=new A.aE(58565,"MaterialIcons",null,!1)
B.avp=new A.ib("Indices & ETFs","\u0418\u043d\u0434\u0435\u043a\u0441\u044b \u0438 ETF","\xcdndices e ETFs","\xcdndices y ETFs","Indices track groups of stocks (e.g. S&P 500). ETFs let you trade a basket in one instrument \u2014 useful for diversification.","\u0418\u043d\u0434\u0435\u043a\u0441\u044b \u043e\u0442\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u044e\u0442 \u0433\u0440\u0443\u043f\u043f\u044b \u0430\u043a\u0446\u0438\u0439 (\u043d\u0430\u043f\u0440. S&P 500). ETF \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u044e\u0442 \u0442\u043e\u0440\u0433\u043e\u0432\u0430\u0442\u044c \u043a\u043e\u0440\u0437\u0438\u043d\u043e\u0439 \u0432 \u043e\u0434\u043d\u043e\u043c \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u0435 \u2014 \u0443\u0434\u043e\u0431\u043d\u043e \u0434\u043b\u044f \u0434\u0438\u0432\u0435\u0440\u0441\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u0438.","\xcdndices acompanham grupos de a\xe7\xf5es (ex. S&P 500). ETFs permitem operar uma cesta em um instrumento \u2014 \xfatil para diversifica\xe7\xe3o.","Los \xedndices siguen grupos de acciones (p. ej. S&P 500). Los ETFs permiten operar una canasta en un instrumento \u2014 \xfatiles para diversificar.",B.Yg)
B.YK=new A.aE(984284,"MaterialIcons",null,!1)
B.avr=new A.ib("Forex basics","\u041e\u0441\u043d\u043e\u0432\u044b Forex","No\xe7\xf5es de Forex","Conceptos de Forex","Forex trades currency pairs like EUR/USD. It is the largest market by volume and operates nearly 24 hours on weekdays.","Forex \u0442\u043e\u0440\u0433\u0443\u0435\u0442 \u0432\u0430\u043b\u044e\u0442\u043d\u044b\u043c\u0438 \u043f\u0430\u0440\u0430\u043c\u0438 \u0432\u0440\u043e\u0434\u0435 EUR/USD. \u042d\u0442\u043e \u043a\u0440\u0443\u043f\u043d\u0435\u0439\u0448\u0438\u0439 \u0440\u044b\u043d\u043e\u043a \u043f\u043e \u043e\u0431\u044a\u0451\u043c\u0443, \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u043f\u043e\u0447\u0442\u0438 24 \u0447\u0430\u0441\u0430 \u0432 \u0431\u0443\u0434\u043d\u0438.","Forex opera pares de moedas como EUR/USD. \xc9 o maior mercado em volume e funciona quase 24 horas nos dias \xfateis.","Forex opera pares de divisas como EUR/USD. Es el mercado m\xe1s grande por volumen y opera casi 24 horas entre semana.",B.YK)
B.YG=new A.aE(62638,"MaterialIcons",null,!1)
B.avl=new A.ib("Risk disclaimer","\u041f\u0440\u0435\u0434\u0443\u043f\u0440\u0435\u0436\u0434\u0435\u043d\u0438\u0435 \u043e \u0440\u0438\u0441\u043a\u0430\u0445","Aviso de risco","Aviso de riesgo","Trading involves substantial risk. This app is for education only \u2014 never trade with money you cannot afford to lose.","\u0422\u0440\u0435\u0439\u0434\u0438\u043d\u0433 \u0441\u0432\u044f\u0437\u0430\u043d \u0441 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c \u0440\u0438\u0441\u043a\u043e\u043c. \u042d\u0442\u043e \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0434\u043b\u044f \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044f \u2014 \u043d\u0435 \u0442\u043e\u0440\u0433\u0443\u0439\u0442\u0435 \u0434\u0435\u043d\u044c\u0433\u0430\u043c\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043d\u0435 \u043c\u043e\u0436\u0435\u0442\u0435 \u043f\u043e\u0442\u0435\u0440\u044f\u0442\u044c.","Trading envolve risco substancial. Este app \xe9 apenas educacional \u2014 nunca opere com dinheiro que n\xe3o pode perder.","El trading implica riesgo sustancial. Esta app es solo educativa \u2014 nunca operes con dinero que no puedas perder.",B.YG)
